subtopics.syntax:
# Basic syntax
for variable in sequence:
    # body

# With range
for i in range(start, stop, step):
    print(i)

# With enumerate (index + value)
for index, value in enumerate(sequence, start=0):
    print(index, value)

# With zip (multiple sequences)
for a, b in zip(seq1, seq2):
    print(a, b)

# Loop over dict
for key, value in dictionary.items():
    print(key, value)

# Basic while
while condition:
    # body
    # MUST change condition or infinite loop!

# Infinite loop with break
while True:
    if exit_condition:
        break

# while with else
while condition:
    # body
else:
    # runs if condition became False (not if break)

# break - exit loop
for i in range(10):
    if i == 5:
        break  # exits when i=5

# continue - skip iteration
for i in range(10):
    if i % 2 == 0:
        continue  # skip even numbers
    print(i)  # only odd numbers

# pass - placeholder
for i in range(5):
    pass  # empty loop (does nothing)

for i in range(outer):
    for j in range(inner):
        # runs outer × inner times total
        print(i, j)

# Time complexity: O(n²)
# For n=100: 100 × 100 = 10,000 iterations
